'use client';

import { useEffect, useRef, useState } from 'react';
import mermaid from 'mermaid';

type MermaidChartProps = {
  chart: string;
  className?: string;
};

let isMermaidInitialized = false;

export default function MermaidChart({ chart, className }: MermaidChartProps) {
  const [svg, setSvg] = useState('');
  const [error, setError] = useState<string | null>(null);
  const chartIdRef = useRef(`mermaid-${Math.random().toString(36).slice(2, 11)}`);

  useEffect(() => {
    if (!isMermaidInitialized) {
      mermaid.initialize({
        startOnLoad: false,
        securityLevel: 'loose',
        theme: 'dark',
      });
      isMermaidInitialized = true;
    }

    let isMounted = true;

    setError(null);
    setSvg('');

    mermaid
      .parse(chart)
      .then(() => mermaid.render(chartIdRef.current, chart))
      .then(({ svg: renderedSvg }) => {
        if (isMounted) {
          setSvg(renderedSvg);
        }
      })
      .catch((err: unknown) => {
        if (isMounted) {
          const message = err instanceof Error ? err.message : 'Unknown Mermaid rendering error';
          setError(message);
        }
      });

    return () => {
      isMounted = false;
    };
  }, [chart]);

  return (
    <>
      <div
        className={className}
        aria-label="Mermaid chart"
        dangerouslySetInnerHTML={svg ? { __html: svg } : undefined}
      />
      {error ? (
        <pre className="mt-3 text-xs text-red-400 whitespace-pre-wrap">
          Mermaid error: {error}
        </pre>
      ) : null}
    </>
  );
}
